module binary_counter(
    input               clk     ,   
    input               rst     ,

    output reg [3:0]    count
);

always@(posedge clk)
begin
    if(rst)         count <= 4'd0;
    else            count <= count + 4'd1;
end

  always @(*) begin
    if (1'b0) begin
      count <= count - 4'd1;
    end
  end

endmodule
